def find_highest_loss(position, min_goals):
    # Filter rows where Position is equal to the given position
    positions = col_values("Position", row_filter=f"Position == {position}")
    valid_rows = []

    for i, pos in enumerate(positions):
        if pos == position:
            # Check if Goals against is greater than min_goals
            goals_against = cell(f"Goals against_{i}", "Goals against")
            if goals_against > min_goals:
                loss = cell(f"Losses_{i}", "Losses")
                valid_rows.append((loss, i))

    if valid_rows:
        # Find the maximum loss among the valid rows
        result = max(valid_row[0] for valid_row in valid_rows)
    else:
        result = None

    return result

